//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFVentAnalysisCmd::MRFVentAnalysisCmd() :
CATStateCommand ("MRFVentAnalysisCmd", CATDlgEngOneShot)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _Indication(NULL)
, _pVentAnalysisDlg(NULL)
, _pVentAnalysisResultDlg(NULL)
, _pSegmentVentDlg(NULL)
, _pSegmentVentServices(NULL)
, _pPitchRefSurfacePathElementAgent(NULL)
, _pSegmentGeometricalSetPathElementAgent(NULL)
, _pVentGeometricalSetPathElementAgent(NULL)
, _pTireAssyPathElementAgent(NULL)
, _pPitchRefSurfaceDialogAgent(NULL)
, _pSegmentGeometricalSetDialogAgent(NULL)
, _pVentGeometricalSetDialogAgent(NULL)
, _pTireAssyDialogAgent(NULL)
, _pPitchRefSurfacePathElement(NULL)
, _pSegmentGeometricalSetPathElement(NULL)
, _pVentGeometricalSetPathElement(NULL)
, _pTireAssyPathElement(NULL)
, _spMechanicalPart(NULL_var)
, _spSelectedPointVentSet(NULL_var)
, _spSelectedSegmentSet(NULL_var)
, _spRemovedVentSet(NULL_var)
, _spMovedVentSet(NULL_var)
, _spMovedSegmentVent(NULL_var)
, _pRefSegmentSurfaceDialogAgent(NULL)
, _pRefSegmentSurfacePathElementAgent(NULL)
, _pRefSegmentSurfacePathElement(NULL)
, _pRefReferenceVentDialogAgent(NULL)
, _pRefReferenceVentPathElement(NULL)
, _pSegmentVentCloseAgent(NULL)
, _pViewResultsDialogState(NULL)
, _pSegmentVentDialogState(NULL)
, _pInitialDialogState(NULL)
, _pResultsCloseDialogAgent(NULL)
, _pViewResultsDialogAgent(NULL)
, _spPitchSurface(NULL_var)
, _pEditor(NULL)
, _pHSO(NULL)
, _pViewer(NULL)
, _spTireAssyObject(NULL_var)
, _pPointBodyDistance(NULL)
{
	_pVentAnalysisDlg = new MRFVentAnalysisDlg();
	_pVentAnalysisDlg->Build();
	
	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();

		CATPathElement  oActivePath = _pEditor->GetUIActiveObject();
		oActivePath.InitToLeafElement();
		_spCBUOnCurrObject = oActivePath.NextFatherElement();

		if (NULL_var != _spCBUOnCurrObject)
		{
			CATIMmiUsePrtPart * piPrtPart = NULL;
			_spCBUOnCurrObject->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
			if (NULL != piPrtPart && NULL_var == _spMechanicalPart)
			{
				_spMechanicalPart = piPrtPart;
				piPrtPart->Release();  piPrtPart = NULL;
			}
		}
	}
	_VentAnalysisType = 0;
	_SegmentVentModified = CATTrue;

	_pViewer = CATViewer::GetCurrentViewer();

}

