//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFVentAnalysisCmd::BuildGraph()
{
	AddAnalyseNotificationCB(_pVentAnalysisDlg, _pVentAnalysisDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFVentAnalysisCmd::ActionOne, NULL);
	AddAnalyseNotificationCB(_pVentAnalysisDlg, _pVentAnalysisDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFVentAnalysisCmd::ActionClose, NULL);
	AddAnalyseNotificationCB(_pVentAnalysisDlg, _pVentAnalysisDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFVentAnalysisCmd::ActionClose, NULL);

	CATDlgRadioButton * pSegmentRadio = _pVentAnalysisDlg->GetSegmentRadioButton();
	if (NULL != pSegmentRadio)
	{
		AddAnalyseNotificationCB(pSegmentRadio, pSegmentRadio->GetRadBModifyNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::ShowVentAnalysisFrame, NULL);
		pSegmentRadio->SetState(CATDlgCheck);
	}
	/*CATDlgRadioButton * pPitchRadio = _pVentAnalysisDlg->GetPitchRadioButton();
	if (NULL != pPitchRadio)
	{
		AddAnalyseNotificationCB(pPitchRadio, pPitchRadio->GetRadBModifyNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::ShowVentAnalysisFrame, NULL);
	}*/
	CATDlgPushButton * pRunAnalysisButton = _pVentAnalysisDlg->GetAnalysisButton();
	if (NULL != pRunAnalysisButton)
	{
		AddAnalyseNotificationCB(pRunAnalysisButton, pRunAnalysisButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnPushAnalysis, NULL);
	}
	CATDlgPushButton * pResetVentsButton = _pVentAnalysisDlg->GetResetVentsButton();
	if (NULL != pResetVentsButton)
	{
		AddAnalyseNotificationCB(pResetVentsButton, pResetVentsButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnResetVents, NULL);
	}
	_pVentGeometricalSetPathElementAgent = new CATPathElementAgent("VentGeometricalSetPathElementAgent");
	if (_pVentGeometricalSetPathElementAgent)
	{
		_pVentGeometricalSetPathElementAgent->AddOrderedElementType("CATIBodyRequest");
		_pVentGeometricalSetPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}
	_pVentGeometricalSetDialogAgent = new CATDialogAgent("VentGeometricalSetDialogAgent");
	if (_pVentGeometricalSetDialogAgent)
	{
		CATDlgSelectorList * pVentGeomSetSelector = NULL;
		pVentGeomSetSelector = _pVentAnalysisDlg->GetVentGeometricalSet();
		if (NULL != pVentGeomSetSelector)
		{
			_pVentGeometricalSetDialogAgent->AcceptOnNotify(pVentGeomSetSelector, pVentGeomSetSelector->GetListSelectNotification());
		}
	}

	_pSegmentGeometricalSetPathElementAgent = new CATPathElementAgent("SegmentGeometricalSetPathElementAgent");
	if (_pSegmentGeometricalSetPathElementAgent)
	{
		_pSegmentGeometricalSetPathElementAgent->AddOrderedElementType("CATIBodyRequest");
		_pSegmentGeometricalSetPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}
	_pSegmentGeometricalSetDialogAgent = new CATDialogAgent("VentGeometricalSetDialogAgent");
	if (_pSegmentGeometricalSetDialogAgent)
	{
		CATDlgSelectorList * pSegmentCuttingGeomSetSelector = NULL;
		pSegmentCuttingGeomSetSelector = _pVentAnalysisDlg->GetSegmentGeometricalSet();
		if (NULL != pSegmentCuttingGeomSetSelector)
		{
			_pSegmentGeometricalSetDialogAgent->AcceptOnNotify(pSegmentCuttingGeomSetSelector, pSegmentCuttingGeomSetSelector->GetListSelectNotification());
		}
	}

	_pTireAssyPathElementAgent = new CATPathElementAgent("TireAssyPathElementAgent");
	if (_pTireAssyPathElementAgent)
	{
		_pTireAssyPathElementAgent->AddOrderedElementType("CATI3DGeometricalElement");
		_pTireAssyPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}
	_pTireAssyDialogAgent = new CATDialogAgent("TireAssyDialogAgent");
	if (_pTireAssyDialogAgent)
	{
		CATDlgSelectorList * pTireAssySelector = NULL;
		pTireAssySelector = _pVentAnalysisDlg->GetTireAssembly();
		if (NULL != pTireAssySelector)
		{
			_pTireAssyDialogAgent->AcceptOnNotify(pTireAssySelector, pTireAssySelector->GetListSelectNotification());
		}
	}

	_pPitchRefSurfacePathElementAgent = new CATPathElementAgent("PitchRefSurfaceElementAgent");
	if (_pPitchRefSurfacePathElementAgent)
	{
		CATListOfCATString ListSurfaces = GetSurfaceSelectorTypes();

		_pPitchRefSurfacePathElementAgent->SetOrderedTypeList(ListSurfaces);
		_pPitchRefSurfacePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}
	_pPitchRefSurfaceDialogAgent = new CATDialogAgent("PitchRefSurfaceDialogAgent");
	if (_pPitchRefSurfaceDialogAgent)
	{
		CATDlgSelectorList* pRefSurfSelector = NULL;
		pRefSurfSelector = _pVentAnalysisDlg->GetReferenceSurface();
		if (NULL != pRefSurfSelector)
		{
			_pPitchRefSurfaceDialogAgent->AcceptOnNotify(pRefSurfSelector, pRefSurfSelector->GetListSelectNotification());
		}
	}

	_pViewResultsDialogAgent = new CATDialogAgent("ViewResultDialogAgent");
	if (_pViewResultsDialogAgent)
	{
		CATDlgPushButton * pViewResults = _pVentAnalysisDlg->GetViewResultsButton();
		if (NULL != pViewResults)
		{
			_pViewResultsDialogAgent->AcceptOnNotify(pViewResults, pViewResults->GetPushBActivateNotification());
			//AddAnalyseNotificationCB(pViewResults, pViewResults->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnViewResultsPush, NULL);
			pViewResults->SetSensitivity(CATDlgDisable);
		}
	}

	_pInitialDialogState = GetInitialState("InitialState");
	_pInitialDialogState->AddDialogAgent(_pVentGeometricalSetDialogAgent);
	_pInitialDialogState->AddDialogAgent(_pVentGeometricalSetPathElementAgent);
	_pInitialDialogState->AddDialogAgent(_pSegmentGeometricalSetDialogAgent);
	_pInitialDialogState->AddDialogAgent(_pTireAssyDialogAgent);
	_pInitialDialogState->AddDialogAgent(_pPitchRefSurfaceDialogAgent);
	_pInitialDialogState->AddDialogAgent(_pViewResultsDialogAgent);

	CATDialogState * pSegmentSetState = AddDialogState("SegmentSetState");
	pSegmentSetState->AddDialogAgent(_pSegmentGeometricalSetDialogAgent);
	pSegmentSetState->AddDialogAgent(_pSegmentGeometricalSetPathElementAgent);
	pSegmentSetState->AddDialogAgent(_pVentGeometricalSetDialogAgent);
	pSegmentSetState->AddDialogAgent(_pTireAssyDialogAgent);
	pSegmentSetState->AddDialogAgent(_pViewResultsDialogAgent);

	CATDialogState * pTireAssyState = AddDialogState("TireAssyState");
	pTireAssyState->AddDialogAgent(_pTireAssyDialogAgent);
	pTireAssyState->AddDialogAgent(_pTireAssyPathElementAgent);
	pTireAssyState->AddDialogAgent(_pVentGeometricalSetDialogAgent);
	pTireAssyState->AddDialogAgent(_pSegmentGeometricalSetDialogAgent);
	pTireAssyState->AddDialogAgent(_pViewResultsDialogAgent);

	CATDialogState * pRefSurfaceState = AddDialogState("RefSurfaceState");
	pRefSurfaceState->AddDialogAgent(_pPitchRefSurfaceDialogAgent);
	pRefSurfaceState->AddDialogAgent(_pPitchRefSurfacePathElementAgent);
	pRefSurfaceState->AddDialogAgent(_pVentGeometricalSetDialogAgent);
	pRefSurfaceState->AddDialogAgent(_pViewResultsDialogAgent);

	_pViewResultsDialogState = AddDialogState("ViewResultsState");
	_pViewResultsDialogState->AddDialogAgent(_pViewResultsDialogAgent);
	_pViewResultsDialogState->AddDialogAgent(_pVentGeometricalSetDialogAgent);
	_pViewResultsDialogState->AddDialogAgent(_pSegmentGeometricalSetDialogAgent);
	_pViewResultsDialogState->AddDialogAgent(_pTireAssyDialogAgent);


	AddTransition(_pInitialDialogState, _pInitialDialogState, IsOutputSetCondition(_pVentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnVentSetSelectorList));
	AddTransition(pSegmentSetState, _pInitialDialogState, IsOutputSetCondition(_pVentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnVentSetSelectorList));
	AddTransition(pTireAssyState, _pInitialDialogState, IsOutputSetCondition(_pVentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnVentSetSelectorList));
	AddTransition(pRefSurfaceState, _pInitialDialogState, IsOutputSetCondition(_pVentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnVentSetSelectorList));
	AddTransition(_pViewResultsDialogState, _pInitialDialogState, IsOutputSetCondition(_pVentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnVentSetSelectorList));
	AddTransition(_pInitialDialogState, _pInitialDialogState, IsOutputSetCondition(_pVentGeometricalSetPathElementAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnVentSetSelection));

	AddTransition(_pInitialDialogState, pSegmentSetState, IsOutputSetCondition(_pSegmentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSetSelectorList));
	AddTransition(pSegmentSetState, pSegmentSetState, IsOutputSetCondition(_pSegmentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSetSelectorList));
	AddTransition(pTireAssyState, pSegmentSetState, IsOutputSetCondition(_pSegmentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSetSelectorList));
	AddTransition(_pViewResultsDialogState, pSegmentSetState, IsOutputSetCondition(_pSegmentGeometricalSetDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSetSelectorList));
	AddTransition(pSegmentSetState, pSegmentSetState, IsOutputSetCondition(_pSegmentGeometricalSetPathElementAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSetSelection));

	AddTransition(_pInitialDialogState, pTireAssyState, IsOutputSetCondition(_pTireAssyDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnTireAssySelectorList));
	AddTransition(pSegmentSetState, pTireAssyState, IsOutputSetCondition(_pTireAssyDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnTireAssySelectorList));
	AddTransition(pTireAssyState, pTireAssyState, IsOutputSetCondition(_pTireAssyDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnTireAssySelectorList));
	AddTransition(_pViewResultsDialogState, pTireAssyState, IsOutputSetCondition(_pTireAssyDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnTireAssySelectorList));
	AddTransition(pTireAssyState, pTireAssyState, IsOutputSetCondition(_pTireAssyPathElementAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnTireAssySelection));

	AddTransition(_pInitialDialogState, pRefSurfaceState, IsOutputSetCondition(_pPitchRefSurfaceDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSurfaceSelectorList));
	AddTransition(pRefSurfaceState, pRefSurfaceState, IsOutputSetCondition(_pPitchRefSurfaceDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSurfaceSelectorList));
	AddTransition(_pViewResultsDialogState, pRefSurfaceState, IsOutputSetCondition(_pPitchRefSurfaceDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSurfaceSelectorList));
	AddTransition(pRefSurfaceState, pRefSurfaceState, IsOutputSetCondition(_pPitchRefSurfacePathElementAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSurfaceSelection));

	AddTransition(_pInitialDialogState, _pViewResultsDialogState, IsOutputSetCondition(_pViewResultsDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnViewResultsPush));
	AddTransition(pTireAssyState, _pViewResultsDialogState, IsOutputSetCondition(_pViewResultsDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnViewResultsPush));
	AddTransition(pSegmentSetState, _pViewResultsDialogState, IsOutputSetCondition(_pViewResultsDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnViewResultsPush));
	AddTransition(_pViewResultsDialogState, _pViewResultsDialogState, IsOutputSetCondition(_pViewResultsDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnViewResultsPush));
	AddTransition(pRefSurfaceState, _pViewResultsDialogState, IsOutputSetCondition(_pViewResultsDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnViewResultsPush));

	CATDlgCheckButton * pGroupVentsCheck = _pVentAnalysisDlg->GetGropuVentsCheck();
	if (NULL != pGroupVentsCheck)
	{
		AddAnalyseNotificationCB(pGroupVentsCheck, pGroupVentsCheck->GetChkBModifyNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnGroupVentsCheck, NULL);
	}

	CATDlgPushButton * pGroupVentsButton = _pVentAnalysisDlg->GetGropuVentButton();
	if (NULL != pGroupVentsButton)
	{
		AddAnalyseNotificationCB(pGroupVentsButton, pGroupVentsButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnGroupVentsPush, NULL);
	}
	CATDlgPushButton * pResetGroupedVentsButton = _pVentAnalysisDlg->GetResetGropuButton();
	if (NULL != pResetGroupedVentsButton)
	{
		AddAnalyseNotificationCB(pResetGroupedVentsButton, pResetGroupedVentsButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnResetGroupVentsPush, NULL);
	}
	
	CATDlgPushButton * pExtractVentPointsButton = _pVentAnalysisDlg->GetExtractPointsButton();
	if (NULL != pExtractVentPointsButton)
	{
		AddAnalyseNotificationCB(pExtractVentPointsButton, pExtractVentPointsButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnExtractVentPointsPush, NULL);
	}

	CATDlgPushButton * pExtractVentCircleButton = _pVentAnalysisDlg->GetExtractVentCircleButton();
	if (NULL != pExtractVentCircleButton)
	{
		AddAnalyseNotificationCB(pExtractVentCircleButton, pExtractVentCircleButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnExtractVentCirclePush, NULL);
	}

	CATDlgPushButton * pConvertVentsButton = _pVentAnalysisDlg->GetConvertVentsPush();
	if (NULL != pConvertVentsButton)
	{
		AddAnalyseNotificationCB(pConvertVentsButton, pConvertVentsButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnConvertVentsPush, NULL);
	}

	CATDlgPushButton * pPrefixVentPointButton = _pVentAnalysisDlg->GetPrefixPointVentButton();
	if (NULL != pPrefixVentPointButton)
	{
		AddAnalyseNotificationCB(pPrefixVentPointButton, pPrefixVentPointButton->GetPushBActivateNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::OnPrefixVentPointPush, NULL);
	}
}


