void MRFVentAnalysisCmd::OnReframeON(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATString strCtxMenuParent = (char*)iUsefulData;
	int CharSize = strCtxMenuParent.GetLengthInChar();
	if (CharSize > 0)
	{
		CATIMmiMechanicalFeature_var spMechFeature;
		GetSelectedFeature(strCtxMenuParent, spMechFeature);

		if (NULL_var != spMechFeature)
			ReframeOnObject(spMechFeature);
	}
	else
	{
		if (NULL != _pHSO)
		{
			int hsoSize = _pHSO->GetSize();
			if (hsoSize > 0)
			{
				CATBaseUnknown * pBaseElement = NULL;
				_pHSO->InitElementList();
				pBaseElement = _pHSO->NextElement();
				if (NULL != pBaseElement)
				{
					CATPathElement * pPathElement = (CATPathElement*)pBaseElement;
					if (NULL != pPathElement)
					{
						//pPathElement->InitToLeafElement();
						CATBaseUnknown_var spObject = pPathElement->CurrentElement();
						if (NULL_var != spObject)//= pPathElement->NextFatherElement()
						{
							ReframeOnObject(spObject);
						}
					}
				}
			}
		}
	}
}

void MRFVentAnalysisCmd::ReframeOnObject(CATBaseUnknown_var ispObject)
{
	if (NULL_var != ispObject)
	{
		CATBody_var spBody;
		MRFGenericUtils::GetBodyOfObject(ispObject, spBody);
		if (NULL_var != spBody && NULL != _pViewer)
		{
			CATMathBox MathBoxOnBody = spBody->GetBoundingBox();

			CATMathPoint pPointOnCenter;
			CATMathPoint pointOnHigh;

			MathBoxOnBody.GetBoxCenter(pPointOnCenter);
			MathBoxOnBody.GetHighLimit(pointOnHigh);

			float radius = (float)pPointOnCenter.DistanceTo(pointOnHigh);
			if (radius < 10.f)
				radius = 10.f;

			CAT3DBoundingSphere p3DBoundingSphere(pPointOnCenter, radius);
			CAT3DViewer* p3DViewer = (CAT3DViewer*)_pViewer;
			if (NULL != p3DViewer)
			{
				p3DViewer->ReframeOn(p3DBoundingSphere);
				p3DViewer->Draw();
			}
		}
	}
}

