	{
		_pVentAnalysisResultDlg->ClearOtherPitchVentResults(strCtxMenuParent);
	}

	if (NULL != pDlgMultiList)
	{
		pDlgMultiList->ClearSelect();
	}

	CATIMmiMechanicalFeature_var spObject;
