void MRFVentAnalysisCmd::OnMoveVent(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATString strCtxMenuParent = (char*)iUsefulData;
	CATIMmiMechanicalFeature_var spMechFeature;
	GetSelectedFeature(strCtxMenuParent, spMechFeature);
	ClearSegmentVentValues();
	if (NULL_var != spMechFeature)
	{
		_spReferenceVent = NULL_var;
		_spReferenceVent = spMechFeature;

		if (!!_pEditor)
		{
			MRFGenericUtils::GetUIActivePathElement(_pEditor, _spReferenceVent, _pRefReferenceVentPathElement);
		}
	}
	_pViewResultsDialogState = GetCurrentState();

	_iSegmentVentMode = 0;
	_SegmentVentModified = CATTrue;

	
	_pSegmentVentDlg = new MRFSegmentVentDlg();
	BuildSegmentVentDialog(iUsefulData);

	if (1 == _VentAnalysisType)
	{
		BuildSegmentVentDlgForPitchVent(_spReferenceVent);
	}

	return;
}

//-------------------------------------------------------------------------
// MRFVentAnalysisCmd::Show error message ()
//Input: CATUnicodeString usMessage, 
//Function: It displays the message sent as input as an error in Window.
//-------------------------------------------------------------------------
void MRFVentAnalysisCmd::ShowErrorMessage(CATUnicodeString istrMessage)
{
	CATUnicodeString strWndTitle = "Error";
	if (NULL != _pVentAnalysisDlg)
	{
		CATDlgNotify * pErrPanel = new CATDlgNotify(_pVentAnalysisDlg, "Error", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
		if (NULL != pErrPanel)
		{
			pErrPanel->DisplayBlocked(istrMessage, strWndTitle);
			AddAnalyseNotificationCB(pErrPanel, pErrPanel->GetNfyOKNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::ErrorPushOk, NULL);
		}
		if (pErrPanel)
			pErrPanel->RequestDelayedDestruction();
		pErrPanel = NULL;

	}
}

void MRFVentAnalysisCmd::ErrorPushOk(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	RequestDelayedDestruction();
}

CATBoolean MRFVentAnalysisCmd::IsResultWindowClosed()
{
	CATBoolean bWindow = CATTrue;
	if (!!_pVentAnalysisResultDlg && CATDlgShow == _pVentAnalysisResultDlg->GetVisibility())
	{
		bWindow = CATFalse;
		CATUnicodeString strMessage = "Please close Result Window";
		ShowErrorMessage(strMessage);
	}
	return bWindow;
}

CATBoolean MRFVentAnalysisCmd::BuildSegmentVentDialog(CATCommandClientData iUsefulData)
{
	if (NULL != _pSegmentVentDlg && !!_pViewResultsDialogState)
	{
		AddAnalyseNotificationCB(_pSegmentVentDlg, _pSegmentVentDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFVentAnalysisCmd::OnOkSegmentVent, iUsefulData);
		AddAnalyseNotificationCB(_pSegmentVentDlg, _pSegmentVentDlg->GetDiaPREVIEWNotification(), (CATCommandMethod)& MRFVentAnalysisCmd::OnPreviewSegmentVent, iUsefulData);
		AddAnalyseNotificationCB(_pSegmentVentDlg, _pSegmentVentDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFVentAnalysisCmd::OnCancelSegmentVent, iUsefulData);
		AddAnalyseNotificationCB(_pSegmentVentDlg, _pSegmentVentDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFVentAnalysisCmd::OnCancelSegmentVent, iUsefulData);

		_SegmentVentModified = CATFalse;

		_pRefSegmentSurfaceDialogAgent = new CATDialogAgent("RefSegmentSurfaceDialogAgent");
		if (!!_pRefSegmentSurfaceDialogAgent)
		{
			CATDlgSelectorList* pReferenceSurfaceSelector = NULL;
			pReferenceSurfaceSelector = _pSegmentVentDlg->GetReferenceSurfaceSelector();
			if (NULL != pReferenceSurfaceSelector)
			{
				_pRefSegmentSurfaceDialogAgent->AcceptOnNotify(pReferenceSurfaceSelector, pReferenceSurfaceSelector->GetListSelectNotification());
			}
		}

		_pRefReferenceVentDialogAgent = new CATDialogAgent("ReferenceVentDialogAgent");
		if (!!_pRefReferenceVentDialogAgent)
		{
			CATDlgSelectorList* pReferenceVentSelector = NULL;
			pReferenceVentSelector = _pSegmentVentDlg->GetReferenceVentSelector();
			if (NULL != pReferenceVentSelector)
			{
				_pRefReferenceVentDialogAgent->AcceptOnNotify(pReferenceVentSelector, pReferenceVentSelector->GetListSelectNotification());
				_pSegmentVentDlg->SetFocusOnSelectorList(pReferenceVentSelector);
			}
		}
		CATDlgContextualMenu * pCtxMenuRefVent = _pSegmentVentDlg->GetRefVentCtxMenu();
		if (!!pCtxMenuRefVent)
		{
			AddAnalyseNotificationCB(pCtxMenuRefVent, pCtxMenuRefVent->GetVisibilityNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::InitializeReferenceVentCtxMenu, iUsefulData);
		}

		_pRefSegmentSurfacePathElementAgent = new CATPathElementAgent("RefSegmentSurfacePathElementAgent");
		if (!!_pRefSegmentSurfacePathElementAgent)
		{
			CATListOfCATString ListSurfaces = GetSurfaceSelectorTypes();

			_pRefSegmentSurfacePathElementAgent->SetOrderedTypeList(ListSurfaces);
			_pRefSegmentSurfacePathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		
		CATDlgContextualMenu * pCtxMenuRefSurf = _pSegmentVentDlg->GetRefSurfaceCtxMenu();
		if (!!pCtxMenuRefSurf)
		{
			AddAnalyseNotificationCB(pCtxMenuRefSurf, pCtxMenuRefSurf->GetVisibilityNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::InitializeSegmentSurfaceCtxMenu, NULL);
		}

		CATDlgSpinner* pDeltaU = _pSegmentVentDlg->GetDeltaUSpinner();
		if (!!pDeltaU)
		{
			AddAnalyseNotificationCB(pDeltaU, pDeltaU->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::SetSegmentVentModified, NULL);
		}
		CATDlgSpinner* pDeltaV = _pSegmentVentDlg->GetDeltaVSpinner();
		if (!!pDeltaV)
		{
			AddAnalyseNotificationCB(pDeltaV, pDeltaV->GetSpinnerModifyNotification(), (CATCommandMethod)&MRFVentAnalysisCmd::SetSegmentVentModified, NULL);
		}

		_pSegmentVentCloseAgent = new CATDialogAgent("SegmentVentCloseDialogAgent");
		if (!!_pSegmentVentCloseAgent)
		{
			_pSegmentVentCloseAgent->AcceptOnNotify(_pSegmentVentDlg, _pSegmentVentDlg->GetDiaOKNotification());
			_pSegmentVentCloseAgent->AcceptOnNotify(_pSegmentVentDlg, _pSegmentVentDlg->GetDiaCANCELNotification());
			_pSegmentVentCloseAgent->AcceptOnNotify(_pSegmentVentDlg, _pSegmentVentDlg->GetWindCloseNotification());
		}

		CATDialogState * pSegmentSurfaceState = AddDialogState("SegmentSurfaceState");
		pSegmentSurfaceState->AddDialogAgent(_pRefSegmentSurfaceDialogAgent);
		pSegmentSurfaceState->AddDialogAgent(_pRefSegmentSurfacePathElementAgent);
		pSegmentSurfaceState->AddDialogAgent(_pRefReferenceVentDialogAgent);
		pSegmentSurfaceState->AddDialogAgent(_pSegmentVentCloseAgent);

		
		_pSegmentVentDialogState = AddDialogState("ReferenceVentState");
		if (!!_pSegmentVentDialogState)
		{
			_pSegmentVentDialogState->AddDialogAgent(_pRefReferenceVentDialogAgent);
			_pSegmentVentDialogState->AddDialogAgent(_pRefSegmentSurfaceDialogAgent);
			_pSegmentVentDialogState->AddDialogAgent(_pSegmentVentCloseAgent);

			_pViewResultsDialogState->AddDialogAgent(_pRefReferenceVentDialogAgent);
			_pViewResultsDialogState->AddDialogAgent(_pSegmentVentCloseAgent);

			AddTransition(pSegmentSurfaceState, pSegmentSurfaceState, IsOutputSetCondition(_pRefSegmentSurfaceDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSurfaceSelectorList));
			AddTransition(_pSegmentVentDialogState, pSegmentSurfaceState, IsOutputSetCondition(_pRefSegmentSurfaceDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSurfaceSelectorList));

			if (0 == _VentAnalysisType)
				AddTransition(pSegmentSurfaceState, pSegmentSurfaceState, IsOutputSetCondition(_pRefSegmentSurfacePathElementAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentSurfaceSelection));

			AddTransition(_pViewResultsDialogState, _pSegmentVentDialogState, IsOutputSetCondition(_pRefReferenceVentDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentReferenceVentSelectorList));
			AddTransition(pSegmentSurfaceState, _pSegmentVentDialogState, IsOutputSetCondition(_pRefReferenceVentDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentReferenceVentSelectorList));
			AddTransition(_pSegmentVentDialogState, _pSegmentVentDialogState, IsOutputSetCondition(_pRefReferenceVentDialogAgent), Action((ActionMethod)&MRFVentAnalysisCmd::OnSegmentReferenceVentSelectorList));

			AddTransition(pSegmentSurfaceState, _pViewResultsDialogState, IsOutputSetCondition(_pSegmentVentCloseAgent), Action((ActionMethod)&MRFVentAnalysisCmd::InitializeMoveCloseAgent));
			AddTransition(_pSegmentVentDialogState, _pViewResultsDialogState, IsOutputSetCondition(_pSegmentVentCloseAgent), Action((ActionMethod)&MRFVentAnalysisCmd::InitializeMoveCloseAgent));


			CATIAlias_var spRefVentAlias = _spReferenceVent;
			if (NULL_var != spRefVentAlias)
			{
				CATUnicodeString strAliasRefVent = spRefVentAlias->GetAlias();
				CATDlgSelectorList* pRefVentSelector = _pSegmentVentDlg->GetReferenceVentSelector();
				if (NULL != pRefVentSelector)
				{
					pRefVentSelector->ClearLine();
					pRefVentSelector->SetLine(strAliasRefVent);
					int isel = 0;
					pRefVentSelector->SetSelect(&isel, 1);
				}
			}

			if (0 == _iSegmentVentMode)
			{
				_pVentAnalysisDlg->SetVisibility(CATDlgHide);
				_pVentAnalysisResultDlg->SetVisibility(CATDlgHide);
				_pSegmentVentDlg->SetVisibility(CATDlgShow);

			}
		}
	}
	return CATTrue;
}
CATBoolean MRFVentAnalysisCmd::MoveSelectedVent(CATBaseUnknown_var ispSelectedVent)
{
	CATIMmiMechanicalFeature_var spMechFeature = ispSelectedVent;

	if (NULL_var == _spMovedVentSet)
	{
		CATIMmiUsePrtPart * pIPrtPart = NULL;
		if (NULL_var != _spMechanicalPart)
		{
			_spMechanicalPart->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&pIPrtPart);
		}
		if (NULL != pIPrtPart)
		{
			CATIGSMTool * piGSMTool = NULL;
			MRFGenericUtils::CreateGSMTool(pIPrtPart, piGSMTool, TRUE, "MovedPointVents");
			if (NULL != piGSMTool)
			{
				_spMovedVentSet = piGSMTool;
				_spMovedVentSet->ChangeMechanicalFather(_spSelectedPointVentSet);

				piGSMTool->Release(); piGSMTool = NULL;
			}
			pIPrtPart->Release(); pIPrtPart = NULL;
		}
	}

	if (NULL_var != spMechFeature && NULL_var != _spMovedVentSet)
	{
		spMechFeature->ChangeMechanicalFather(_spMovedVentSet);
		_ListOfMovedVents.Append(spMechFeature);
		_ListOfMRFPointVents.RemoveValue(spMechFeature);		
	}
	return CATTrue;
}

void MRFVentAnalysisCmd::OnPreviewSegmentVent(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	CATString istrUsefulData = (char*)iUsefulData;

	if (_SegmentVentModified)
	{
		if (0 == _VentAnalysisType)
		{
			if (0 == _iSegmentVentMode)
			{
				CreateSegmentVentFeature();
				if (NULL_var != _spReferenceVent)
					MoveSelectedVent(_spReferenceVent);
			}
			else if (1 == _iSegmentVentMode)
			{
				UpdateSegmentVentFeature(_spMovedSegmentVent);
			}
		}
		else if (1 == _VentAnalysisType)
		{
			UpdatePitchPointVent();
		}

		if (0 == _iSegmentVentMode)
		{
			UpdateInMultiList(istrUsefulData, "Moved");
			_iSegmentVentMode = 1;
		}
		_SegmentVentModified = CATFalse;
	}
	return;
}

void MRFVentAnalysisCmd::OnOkSegmentVent(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	
	if (_SegmentVentModified && NULL_var != _spReferenceSegmentSurface)
	{
		OnPreviewSegmentVent(ipCommand, ipNotification, iUsefulData);
	}
	OnCancelSegmentVent(ipCommand, ipNotification, iUsefulData);
	
	return;
}

void MRFVentAnalysisCmd::OnCancelSegmentVent(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	if (NULL != _pSegmentVentDlg)
	{
		_pSegmentVentDlg->RequestDelayedDestruction();
		_pSegmentVentDlg = NULL;

		if (!!_pVentAnalysisDlg && !!_pVentAnalysisResultDlg)
		{
			_pVentAnalysisDlg->SetVisibility(CATDlgShow);
			_pVentAnalysisResultDlg->SetVisibility(CATDlgShow);
		}
	}
}
