//-------------------------------------------------------------------------
// OnSurfaceSelection ()
// Launched when user selects as Surface
//-------------------------------------------------------------------------
CATBoolean MRFVentAnalysisCmd::OnSegmentSurfaceSelection(void * data)
{
	if (NULL != _pRefSegmentSurfacePathElementAgent)
	{
		_pRefSegmentSurfacePathElement = _pRefSegmentSurfacePathElementAgent->GetValue();

		if (!!_pRefSegmentSurfacePathElement)
		{
			if (NULL != _pHSO)
			{
				_pHSO->Empty();
				if (0 == _pHSO->IsMember(_pRefSegmentSurfacePathElement))
					_pHSO->AddElement(_pRefSegmentSurfacePathElement);
			}
			CATUnicodeString strSurfaceName;
			CATIMmiMechanicalFeature_var spSurfaceObject;
			FeaturizeSubElement(_pRefSegmentSurfacePathElement, spSurfaceObject, strSurfaceName);
			if (NULL_var != spSurfaceObject)
			{
				if (ValidateSelectedSurface(spSurfaceObject, _spReferenceVent))
				{
					_spReferenceSegmentSurface = spSurfaceObject;
					_SegmentVentModified = CATTrue;

					if (!!_pSegmentVentDlg)
					{
						CATIAlias_var spRefSurfaceAlias = _spReferenceSegmentSurface;
						if (NULL_var != spRefSurfaceAlias)
						{
							CATDlgSelectorList* pReferenceSurfaceSelector = _pSegmentVentDlg->GetReferenceSurfaceSelector();
							if (NULL != pReferenceSurfaceSelector)
							{
								pReferenceSurfaceSelector->ClearLine();
								pReferenceSurfaceSelector->SetLine(strSurfaceName);
								_pSegmentVentDlg->SetFocusOnSelectorList(pReferenceSurfaceSelector);
								_SegmentVentModified = CATTrue;
							}
						}
					}
				}
				else
				{
					ClearSegmentSurface(NULL, NULL, NULL);
					CATUnicodeString strMessage = "Reference Vent does not lie on selected Surface.\nPlease reselect the surface.";
					ShowErrorMessage(strMessage);
					_SegmentVentModified = CATFalse;
				}
			}
		}
	}

	if (!!_pRefSegmentSurfacePathElementAgent)
		_pRefSegmentSurfacePathElementAgent->InitializeAcquisition();


	return CATTrue;
}

void MRFVentAnalysisCmd::FeaturizeSubElement(CATPathElement * ipSelectedPathElement, CATIMmiMechanicalFeature_var & ospMechanicalFeature, CATUnicodeString & oSelectedFeatureName)
{
	if (NULL != ipSelectedPathElement)
	{
		CATBaseUnknown_var spMainElement = ipSelectedPathElement->CurrentElement();
		CATCell_var spSelectedCell;
		CATBaseUnknown_var spLastElement;

		ipSelectedPathElement->InitToLeafElement();

		if (NULL_var != (spLastElement = ipSelectedPathElement->NextFatherElement()))
		{
			if (NULL_var != spLastElement)
			{
				ospMechanicalFeature = spLastElement;

				if (NULL_var != ospMechanicalFeature)
				{
					CATIAlias_var spAliasOnLastElement = ospMechanicalFeature;
					if (NULL_var != spAliasOnLastElement)
					{
						oSelectedFeatureName = spAliasOnLastElement->GetAlias();
					}
				}
				else
				{
					CATIMmiUseBRepAccess_var spBRepAccess = spLastElement;
					if (NULL_var != spBRepAccess)
					{
						spBRepAccess->GetBRepSelectingCell(spSelectedCell);
					}

					if (NULL_var != spSelectedCell && NULL_var != spMainElement)
					{
						MRFGenericUtils::FeaturizeSubElement(spSelectedCell, spMainElement, ospMechanicalFeature);
						if (NULL_var != ospMechanicalFeature)
						{
							CATIAlias_var spAliasOnMainElement = spMainElement;
							CATIAlias_var spAliasOnLastElement = ospMechanicalFeature;

							oSelectedFeatureName = spAliasOnMainElement->GetAlias() + "/" + spAliasOnLastElement->GetAlias();
						}
					}
				}
			}
		}
	}
}

